import React, { useState, useEffect, useCallback } from 'react';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';
import s from './RecommendationsPage.module.css';

const COLORS = {
  bg: tokens.color.bg, surface: tokens.color.surface, border: tokens.color.border,
  text: tokens.color.text, muted: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};

const regimeColors = {
  trending_up: COLORS.green,
  trending_down: COLORS.red,
  high_volatility: COLORS.amber,
  range_bound: COLORS.blue,
  mean_reverting: COLORS.purple,
};

const actionColors = {
  add: COLORS.blue,
  review: COLORS.amber,
  regime_warning: COLORS.red,
};

const statusColors = {
  pending: COLORS.amber,
  approved: COLORS.green,
  rejected: COLORS.red,
};

function Pill({ children, color }) {
  return (
    <span
      className={s.pill}
      style={{ backgroundColor: color, color: COLORS.bg }}
    >
      {children}
    </span>
  );
}

function Badge({ children, color }) {
  return (
    <span
      className={s.badge}
      style={{ backgroundColor: color, color: COLORS.bg }}
    >
      {children}
    </span>
  );
}

function ConfidenceBar({ value }) {
  return (
    <div className={s.confidenceTrack}>
      <div className={s.confidenceFill} style={{ width: `${value}%` }} />
    </div>
  );
}

function ScoreBar({ label, value, color }) {
  return (
    <div className={s.scoreBarWrap}>
      <div className={s.scoreBarLabel} title={label}>
        {label}
      </div>
      <div className={s.scoreBarTrack}>
        <div
          className={s.scoreBarFill}
          style={{ width: `${value}%`, backgroundColor: color }}
        />
      </div>
    </div>
  );
}

function MetricItem({ label, value }) {
  return (
    <div className={s.metricItem} title={`${label}: ${value}`}>
      <span className={s.metricLabel}>{label}: </span>
      <span>{value}</span>
    </div>
  );
}

function StatusPill({ status }) {
  const color = statusColors[status] || COLORS.muted;
  return <Pill color={color}>{status}</Pill>;
}

export default function RecommendationsPage() {
  const [assetClass, setAssetClass] = useState('US');
  const [regime, setRegime] = useState(null);
  const [recommendations, setRecommendations] = useState([]);
  const [loadingRecs, setLoadingRecs] = useState(false);
  const [errorRecs, setErrorRecs] = useState(null);
  const [loadingRegime, setLoadingRegime] = useState(false);
  const [errorRegime, setErrorRegime] = useState(null);
  const [historyTab, setHistoryTab] = useState(false);
  const [historyData, setHistoryData] = useState(null);
  const [loadingHistory, setLoadingHistory] = useState(false);
  const [errorHistory, setErrorHistory] = useState(null);
  const [actionReasons, setActionReasons] = useState({}); // {strategy_key: reason string}
  const [editingReasonKey, setEditingReasonKey] = useState(null);
  const [actionLoading, setActionLoading] = useState({}); // {strategy_key: boolean}
  const [refreshToggle, setRefreshToggle] = useState(false);

  const fetchRegime = useCallback(async () => {
    setLoadingRegime(true);
    setErrorRegime(null);
    try {
      const data = await api('/recommendations/regime');
      if (!data) throw new Error('Failed to fetch regime');
      setRegime(data);
    } catch (e) {
      setErrorRegime(e.message);
      setRegime(null);
    } finally {
      setLoadingRegime(false);
    }
  }, []);

  const fetchRecommendations = useCallback(async () => {
    setLoadingRecs(true);
    setErrorRecs(null);
    try {
      const data = await api(`/recommendations?asset_class=${assetClass.toLowerCase()}`);
      if (!data) throw new Error('Failed to fetch recommendations');
      setRecommendations(data.recommendations || []);
    } catch (e) {
      setErrorRecs(e.message);
      setRecommendations([]);
    } finally {
      setLoadingRecs(false);
    }
  }, [assetClass]);

  const fetchHistory = useCallback(async () => {
    setLoadingHistory(true);
    setErrorHistory(null);
    try {
      const data = await api('/recommendations/history?limit=100');
      if (!data) throw new Error('Failed to fetch history');
      setHistoryData(data);
    } catch (e) {
      setErrorHistory(e.message);
      setHistoryData(null);
    } finally {
      setLoadingHistory(false);
    }
  }, []);

  useEffect(() => {
    fetchRegime();
  }, [fetchRegime, refreshToggle]);

  useEffect(() => {
    fetchRecommendations();
  }, [fetchRecommendations, refreshToggle, assetClass]);

  useEffect(() => {
    if (historyTab) fetchHistory();
  }, [historyTab, fetchHistory, refreshToggle]);

  const onApprove = async (strategy_key) => {
    if (!actionReasons[strategy_key] || actionReasons[strategy_key].trim() === '') {
      alert('Please provide a reason before approving.');
      return;
    }
    setActionLoading((s) => ({ ...s, [strategy_key]: true }));
    try {
      const data = await api(`/recommendations/${strategy_key}/approve`, {
        method: 'POST',
        body: JSON.stringify({ reason: actionReasons[strategy_key] }),
      });
      if (!data) throw new Error('Approve failed');
      if (data.ok) {
        setRecommendations((recs) =>
          recs.map((r) =>
            r.strategy_key === strategy_key ? { ...r, status: data.status } : r
          )
        );
        setEditingReasonKey(null);
      } else {
        alert('Approve failed');
      }
    } catch (e) {
      alert(e.message);
    } finally {
      setActionLoading((s) => ({ ...s, [strategy_key]: false }));
    }
  };

  const onReject = async (strategy_key) => {
    if (!actionReasons[strategy_key] || actionReasons[strategy_key].trim() === '') {
      alert('Please provide a reason before rejecting.');
      return;
    }
    setActionLoading((s) => ({ ...s, [strategy_key]: true }));
    try {
      const data = await api(`/recommendations/${strategy_key}/reject`, {
        method: 'POST',
        body: JSON.stringify({ reason: actionReasons[strategy_key] }),
      });
      if (!data) throw new Error('Reject failed');
      if (data.ok) {
        setRecommendations((recs) =>
          recs.map((r) =>
            r.strategy_key === strategy_key ? { ...r, status: data.status } : r
          )
        );
        setEditingReasonKey(null);
      } else {
        alert('Reject failed');
      }
    } catch (e) {
      alert(e.message);
    } finally {
      setActionLoading((s) => ({ ...s, [strategy_key]: false }));
    }
  };

  const regimeColor = regime ? regimeColors[regime.regime] || COLORS.muted : COLORS.muted;

  return (
    <div className={s.page}>
      {/* Header: Asset Class Toggle + Refresh + Tabs */}
      <header className={s.header}>
        <div className={s.toggleGroup}>
          {['US', 'Crypto'].map((cls) => (
            <button
              key={cls}
              onClick={() => setAssetClass(cls)}
              className={s.toggleBtn}
              style={{
                backgroundColor: assetClass === cls ? COLORS.surface : COLORS.border,
                color: assetClass === cls ? COLORS.blue : COLORS.muted,
              }}
              type="button"
              aria-pressed={assetClass === cls}
            >
              {cls}
            </button>
          ))}
        </div>
        <button
          onClick={() => setRefreshToggle((v) => !v)}
          className={s.refreshBtn}
          type="button"
          aria-label="Refresh data"
        >
          Refresh
        </button>
        <nav aria-label="Page tabs" className={s.tabNav}>
          <button
            onClick={() => setHistoryTab(false)}
            className={s.tabBtn}
            style={{
              backgroundColor: !historyTab ? COLORS.surface : COLORS.border,
              color: !historyTab ? COLORS.blue : COLORS.muted,
            }}
            type="button"
            aria-current={!historyTab ? 'page' : undefined}
          >
            Pending Recommendations
          </button>
          <button
            onClick={() => setHistoryTab(true)}
            className={s.tabBtn}
            style={{
              backgroundColor: historyTab ? COLORS.surface : COLORS.border,
              color: historyTab ? COLORS.blue : COLORS.muted,
            }}
            type="button"
            aria-current={historyTab ? 'page' : undefined}
          >
            History
          </button>
        </nav>
      </header>

      {/* Regime Banner */}
      <section aria-label="Current regime information" className={s.regimeSection}>
        {loadingRegime ? (
          <div className={s.statusMessage}>Loading regime...</div>
        ) : errorRegime ? (
          <div className={s.statusMessage}>Regime data unavailable</div>
        ) : regime ? (
          <>
            <div className={s.regimeRow}>
              <div className={s.regimeTitle} style={{ color: regimeColor }} title="Current regime">
                {regime.regime.replace(/_/g, ' ')}
              </div>
              <div className={s.regimeMeta} title="Confidence">
                Confidence: {(regime.confidence * 100).toFixed(1)}%
              </div>
              <div className={s.regimeMeta} title="Reference symbol">
                Reference: {regime.reference_symbol}
              </div>
              <div className={s.regimeMeta} title="MA20">
                MA20: {regime.computed?.ma20?.toFixed(2) ?? '--'}
              </div>
              <div className={s.regimeMeta} title="MA50">
                MA50: {regime.computed?.ma50?.toFixed(2) ?? '--'}
              </div>
            </div>
            <div className={s.categoryGroup}>
              {regime.favored_categories?.length > 0 && (
                <div className={s.categoryRow}>
                  <span className={s.categoryLabel} style={{ color: COLORS.green }}>
                    Favored:
                  </span>
                  {regime.favored_categories.map(({ category }) => (
                    <Pill key={`favored-${category}`} color={COLORS.green}>
                      {category}
                    </Pill>
                  ))}
                </div>
              )}
              {regime.avoid_categories?.length > 0 && (
                <div className={s.categoryRow}>
                  <span className={s.categoryLabel} style={{ color: COLORS.red }}>
                    Avoid:
                  </span>
                  {regime.avoid_categories.map(({ category }) => (
                    <Pill key={`avoid-${category}`} color={COLORS.red}>
                      {category}
                    </Pill>
                  ))}
                </div>
              )}
            </div>
          </>
        ) : (
          <div className={s.statusMessage}>No regime data</div>
        )}
      </section>

      {/* Main Content */}
      <main className={s.main}>
        {!historyTab ? (
          <>
            {/* Pending Recommendations */}
            <section aria-label="Pending recommendations">
              {loadingRecs ? (
                <div className={s.statusMessage}>Loading recommendations...</div>
              ) : errorRecs ? (
                <div className={s.errorBlock}>
                  <div className={s.errorIcon}>&#x1F50D;</div>
                  <div className={s.errorTitle}>Unable to load recommendations</div>
                  <div className={s.errorSub}>The recommendations engine may be offline. Try refreshing.</div>
                </div>
              ) : recommendations.length === 0 ? (
                <div className={s.statusMessage}>
                  No pending recommendations for {assetClass}.
                </div>
              ) : (
                <div className={s.recGrid}>
                  {recommendations.map((rec) => {
                    const {
                      id,
                      strategy_key,
                      label,
                      action,
                      reason,
                      confidence,
                      metrics_data,
                      status,
                      created_at,
                    } = rec;
                    const scores = metrics_data?.scores || {};
                    const metrics = metrics_data?.metrics || {};
                    const isEditing = editingReasonKey === strategy_key;
                    const canAct = status === 'pending';
                    return (
                      <article
                        key={strategy_key}
                        className={s.recCard}
                        aria-label={`Recommendation for strategy ${label}`}
                      >
                        <header className={s.recHeader}>
                          <h3 className={s.recTitle} title={label}>
                            {label}
                          </h3>
                          <Badge color={actionColors[action] || COLORS.muted}>{action}</Badge>
                        </header>

                        <div className={s.recReason}>
                          Reason: {reason}
                        </div>

                        <div className={s.recConfidence}>
                          Confidence: {confidence}%
                          <ConfidenceBar value={confidence} />
                        </div>

                        {/* Scores breakdown */}
                        <div className={s.scoresRow} aria-label="Score breakdown">
                          <ScoreBar label="performance" value={scores.performance || 0} color={COLORS.green} />
                          <ScoreBar label="regime_fit" value={scores.regime_fit || 0} color={COLORS.blue} />
                          <ScoreBar label="drawdown" value={scores.drawdown || 0} color={COLORS.red} />
                          <ScoreBar label="consistency" value={scores.consistency || 0} color={COLORS.amber} />
                          <ScoreBar label="diversification" value={scores.diversification || 0} color={COLORS.purple} />
                        </div>

                        {/* Metrics row */}
                        <div className={s.metricsRow}>
                          <MetricItem label="PF" value={metrics.profit_factor?.toFixed(2) ?? 'N/A'} />
                          <MetricItem label="WR%" value={metrics.win_rate != null ? `${Number(metrics.win_rate).toFixed(1)}` : 'N/A'} />
                          <MetricItem label="Avg Return" value={metrics.avg_return != null ? `${(metrics.avg_return * 100).toFixed(2)}%` : 'N/A'} />
                          <MetricItem label="Trades" value={metrics.count ?? 'N/A'} />
                        </div>

                        {/* Approve/Reject + Reason textarea */}
                        {canAct && (
                          <div className={s.actionsWrap}>
                            {isEditing && (
                              <textarea
                                aria-label={`Reason for action on ${label}`}
                                rows={3}
                                value={actionReasons[strategy_key] || ''}
                                onChange={(e) =>
                                  setActionReasons((s) => ({
                                    ...s,
                                    [strategy_key]: e.target.value,
                                  }))
                                }
                                className={s.textarea}
                              />
                            )}
                            <div className={s.btnRow}>
                              {!isEditing && (
                                <button
                                  type="button"
                                  onClick={() => setEditingReasonKey(strategy_key)}
                                  className={s.actionBtn}
                                  style={{ backgroundColor: COLORS.blue, color: COLORS.bg }}
                                >
                                  Add Reason
                                </button>
                              )}
                              {isEditing && (
                                <>
                                  <button
                                    type="button"
                                    onClick={() => onApprove(strategy_key)}
                                    disabled={actionLoading[strategy_key]}
                                    className={s.actionBtn}
                                    style={{
                                      backgroundColor: COLORS.green,
                                      color: COLORS.bg,
                                      cursor: actionLoading[strategy_key] ? 'wait' : 'pointer',
                                    }}
                                  >
                                    {actionLoading[strategy_key] ? 'Approving...' : 'Approve'}
                                  </button>
                                  <button
                                    type="button"
                                    onClick={() => onReject(strategy_key)}
                                    disabled={actionLoading[strategy_key]}
                                    className={s.actionBtn}
                                    style={{
                                      backgroundColor: COLORS.red,
                                      color: COLORS.bg,
                                      cursor: actionLoading[strategy_key] ? 'wait' : 'pointer',
                                    }}
                                  >
                                    {actionLoading[strategy_key] ? 'Rejecting...' : 'Reject'}
                                  </button>
                                  <button
                                    type="button"
                                    onClick={() => setEditingReasonKey(null)}
                                    className={s.cancelBtn}
                                    aria-label="Cancel reason input"
                                  >
                                    Cancel
                                  </button>
                                </>
                              )}
                            </div>
                          </div>
                        )}

                        {!canAct && (
                          <div className={s.statusWrap}>
                            <StatusPill status={status} />
                          </div>
                        )}
                      </article>
                    );
                  })}
                </div>
              )}
            </section>
          </>
        ) : (
          <>
            {/* History Tab */}
            <section aria-label="Recommendation history" className={s.historySection}>
              {loadingHistory ? (
                <div className={s.statusMessage}>Loading history...</div>
              ) : errorHistory ? (
                <div className={s.errorBlock}>
                  <div className={s.errorTitle}>History unavailable</div>
                  <div className={s.errorSub}>Could not load recommendation history. Try refreshing.</div>
                </div>
              ) : historyData && historyData.history.length > 0 ? (
                <table className={s.historyTable}>
                  <thead>
                    <tr>
                      <th className={s.historyTh}>Strategy</th>
                      <th className={s.historyTh}>Status</th>
                      <th className={s.historyTh}>Reason</th>
                      <th className={s.historyTh}>Created At</th>
                    </tr>
                  </thead>
                  <tbody>
                    {historyData.history.map((item) => (
                      <tr key={item.strategy_key + item.created_at} className={s.historyRow}>
                        <td className={s.tdLabel} title={item.label}>
                          {item.label}
                        </td>
                        <td className={s.tdStatus}>
                          <StatusPill status={item.status} />
                        </td>
                        <td className={s.tdReason} title={item.reason}>
                          {item.reason}
                        </td>
                        <td className={s.tdDate} title={new Date(item.created_at).toLocaleString()}>
                          {new Date(item.created_at).toLocaleDateString()}{' '}
                          {new Date(item.created_at).toLocaleTimeString()}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              ) : (
                <div className={s.statusMessage}>
                  No history data available.
                </div>
              )}
            </section>
          </>
        )}
      </main>
    </div>
  );
}
